using System;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests
{
    public static class TestHelper
    {
        public static SchoolContext CreateContext()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
                .Options;

            var context = new SchoolContext(options);
            return context;
        }

        public static SchoolContext CreateSeededContext()
        {
            var context = CreateContext();
            SeedData(context);
            return context;
        }

        public static void SeedData(SchoolContext context)
        {
            var instructor1 = new Instructor
            {
                ID = 1,
                LastName = "Abercrombie",
                FirstMidName = "Kim",
                HireDate = new DateTime(2020, 3, 11)
            };
            var instructor2 = new Instructor
            {
                ID = 2,
                LastName = "Fakhouri",
                FirstMidName = "Fadi",
                HireDate = new DateTime(2019, 7, 6)
            };

            context.Instructors.AddRange(instructor1, instructor2);

            var department1 = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000,
                StartDate = new DateTime(2020, 9, 1),
                InstructorID = 1
            };
            var department2 = new Department
            {
                DepartmentID = 2,
                Name = "Mathematics",
                Budget = 200000,
                StartDate = new DateTime(2019, 9, 1),
                InstructorID = 2
            };

            context.Departments.AddRange(department1, department2);

            var course1 = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            var course2 = new Course
            {
                CourseID = 4022,
                Title = "Microeconomics",
                Credits = 3,
                DepartmentID = 2
            };
            var course3 = new Course
            {
                CourseID = 4041,
                Title = "Macroeconomics",
                Credits = 3,
                DepartmentID = 2
            };

            context.Courses.AddRange(course1, course2, course3);

            var student1 = new Student
            {
                ID = 10,
                LastName = "Alexander",
                FirstMidName = "Carson",
                EnrollmentDate = new DateTime(2021, 9, 1)
            };
            var student2 = new Student
            {
                ID = 11,
                LastName = "Alonso",
                FirstMidName = "Meredith",
                EnrollmentDate = new DateTime(2019, 9, 1)
            };
            var student3 = new Student
            {
                ID = 12,
                LastName = "Anand",
                FirstMidName = "Arturo",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            context.Students.AddRange(student1, student2, student3);

            context.Enrollments.AddRange(
                new Enrollment { EnrollmentID = 1, StudentID = 10, CourseID = 1050, Grade = Grade.A },
                new Enrollment { EnrollmentID = 2, StudentID = 10, CourseID = 4022, Grade = Grade.C },
                new Enrollment { EnrollmentID = 3, StudentID = 11, CourseID = 4041, Grade = Grade.B }
            );

            context.CourseAssignments.AddRange(
                new CourseAssignment { InstructorID = 1, CourseID = 1050 },
                new CourseAssignment { InstructorID = 2, CourseID = 4022 }
            );

            context.SaveChanges();
        }
    }
}

