using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly Data.SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelper.CreateSeededContext();
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewResult_WithPaginatedList()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_SortsByLastName_DefaultOrder()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Alexander", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Anand", model[2].LastName);
        }

        [Fact]
        public void Index_SortsByLastNameDescending()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Anand", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Alexander", model[2].LastName);
        }

        [Fact]
        public void Index_SortsByDateAscending()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Alonso", model[0].LastName); // 2019
            Assert.Equal("Anand", model[1].LastName);  // 2020
            Assert.Equal("Alexander", model[2].LastName); // 2021
        }

        [Fact]
        public void Index_SortsByDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Alexander", model[0].LastName); // 2021
            Assert.Equal("Anand", model[1].LastName);  // 2020
            Assert.Equal("Alonso", model[2].LastName); // 2019
        }

        [Fact]
        public void Index_FiltersStudentsBySearchString()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_FiltersStudentsByFirstName()
        {
            var result = _controller.Index(null, null, "Meredith", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Alonso", model[0].LastName);
        }

        [Fact]
        public void Index_SearchStringNull_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alexander", null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_NewSearchString_ResetsPageTo1()
        {
            var result = _controller.Index(null, null, "A", 3) as ViewResult;

            // When searchString is provided, page should be set to 1
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_SetsViewBagProperties()
        {
            _controller.Index("Date", null, "test", null);

            Assert.Equal("Date", _controller.ViewBag.CurrentSort);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
            Assert.Equal("", _controller.ViewBag.NameSortParm);
            Assert.Equal("test", _controller.ViewBag.CurrentFilter);
        }

        [Fact]
        public void Index_DefaultSort_SetsNameSortParmToNameDesc()
        {
            _controller.Index(null, null, null, null);

            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsStudent()
        {
            var result = _controller.Details(10) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
            Assert.Equal("Carson", student.FirstMidName);
        }

        [Fact]
        public void Details_ValidId_IncludesEnrollments()
        {
            var result = _controller.Details(10) as ViewResult;

            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal(2, student.Enrollments.Count);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithNewStudent()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, student.EnrollmentDate);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_Post_ValidStudent_SavesStudent()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            _controller.Create(student);

            Assert.Equal(4, _context.Students.Count());
            Assert.Contains(_context.Students, s => s.LastName == "Smith");
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsViewWithStudent()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "John",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.IsType<Student>(result.Model);
        }

        [Fact]
        public void Create_Post_MinDateEnrollment_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_DateBefore1753_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John",
                EnrollmentDate = new DateTime(1752, 12, 31)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsStudent()
        {
            var result = _controller.Edit(10) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                ID = 10,
                LastName = "Alexander-Updated",
                FirstMidName = "Carson",
                EnrollmentDate = new DateTime(2021, 9, 1)
            };

            var result = _controller.Edit(student);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 10,
                FirstMidName = "Carson",
                EnrollmentDate = new DateTime(2021, 9, 1)
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_MinDateEnrollment_AddsModelError()
        {
            var student = new Student
            {
                ID = 10,
                LastName = "Alexander",
                FirstMidName = "Carson",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsStudent()
        {
            var result = _controller.Delete(10) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        #endregion

        #region Delete POST

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesStudentAndRedirects()
        {
            var result = _controller.DeleteConfirmed(10);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Equal(2, _context.Students.Count());
            Assert.DoesNotContain(_context.Students, s => s.ID == 10);
        }

        [Fact]
        public void DeleteConfirmed_InvalidId_RedirectsToIndexWithError()
        {
            // Find(999) returns null, accessing properties on null throws
            var result = _controller.DeleteConfirmed(999);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        #endregion
    }
}

