using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestHelper.CreateSeededContext();
            _controller = new DepartmentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewWithAllDepartments()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(result.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Index_IncludesAdministratorData()
        {
            var result = _controller.Index() as ViewResult;

            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(result.Model);
            var engineering = model.First(d => d.Name == "Engineering");
            Assert.NotNull(engineering.Administrator);
            Assert.Equal("Abercrombie", engineering.Administrator.LastName);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
