using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestHelper.CreateSeededContext();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_NoSelection_ReturnsAllInstructors()
        {
            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_ReturnsCourses()
        {
            var result = _controller.Index(1, null) as ViewResult;

            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
            Assert.Equal("Chemistry", model.Courses.First().Title);
        }

        [Fact]
        public void Index_WithInstructorId_SetsViewBagInstructorID()
        {
            _controller.Index(1, null);

            Assert.Equal(1, _controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Index_WithCourseId_ReturnsEnrollments()
        {
            var result = _controller.Index(1, 1050) as ViewResult;

            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Enrollments);
            Assert.Single(model.Enrollments);
        }

        [Fact]
        public void Index_WithCourseId_SetsViewBagCourseID()
        {
            _controller.Index(1, 1050);

            Assert.Equal(1050, _controller.ViewBag.CourseID);
        }

        [Fact]
        public void Index_InstructorsOrderedByLastName()
        {
            var result = _controller.Index(null, null) as ViewResult;

            var model = Assert.IsType<InstructorIndexData>(result.Model);
            var instructors = model.Instructors.ToList();
            Assert.Equal("Abercrombie", instructors[0].LastName);
            Assert.Equal("Fakhouri", instructors[1].LastName);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsInstructor()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithInstructor()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(instructor.CourseAssignments);
            Assert.Empty(instructor.CourseAssignments);
        }

        [Fact]
        public void Create_Get_PopulatesAssignedCourseData()
        {
            _controller.Create();

            var courses = _controller.ViewBag.Courses as List<AssignedCourseData>;
            Assert.NotNull(courses);
            Assert.Equal(3, courses.Count);
            Assert.All(courses, c => Assert.False(c.Assigned));
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                LastName = "Newton",
                FirstMidName = "Isaac",
                HireDate = new DateTime(2022, 1, 15)
            };

            var result = _controller.Create(instructor, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_Post_ValidInstructorWithCourses_SavesCourseAssignments()
        {
            var instructor = new Instructor
            {
                LastName = "Newton",
                FirstMidName = "Isaac",
                HireDate = new DateTime(2022, 1, 15)
            };

            _controller.Create(instructor, new[] { "1050", "4022" });

            var saved = _context.Instructors.First(i => i.LastName == "Newton");
            var assignments = _context.CourseAssignments.Where(ca => ca.InstructorID == saved.ID).ToList();
            Assert.Equal(2, assignments.Count);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "Isaac",
                HireDate = new DateTime(2022, 1, 15)
            };

            var result = _controller.Create(instructor, null) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsInstructor()
        {
            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Abercrombie", instructor.LastName);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsInstructor()
        {
            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        #endregion

        #region Delete POST

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesInstructorAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Single(_context.Instructors);
        }

        [Fact]
        public void DeleteConfirmed_InstructorAsDeptAdmin_NullsDepartmentInstructorID()
        {
            _controller.DeleteConfirmed(1);

            var dept = _context.Departments.Find(1);
            Assert.Null(dept.InstructorID);
        }

        #endregion
    }
}

