using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain the static queue to ensure test isolation
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("Admin", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_WithDisplayName_IncludesNameInMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.Contains("John Doe", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.Contains("ID: 42", notification.Message);
        }

        [Fact]
        public void SendNotification_CreateOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Course", "101", "Math", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("New Course 'Math' has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Course", "101", "Math", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("Course 'Math' has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Course", "101", "Math", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("Course 'Math' has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_SetsCreatedAtToNow()
        {
            var before = DateTime.Now.AddSeconds(-1);
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now.AddSeconds(1);

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void SendNotification_SetsIsReadToFalse()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, null);

            var notification = _service.ReceiveNotification();
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var notification = _service.ReceiveNotification();

            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_MultipleSends_ReturnsInFifoOrder()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            _service.SendNotification("Course", "2", EntityOperation.UPDATE);
            _service.SendNotification("Department", "3", EntityOperation.DELETE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            var third = _service.ReceiveNotification();

            Assert.Equal("Student", first.EntityType);
            Assert.Equal("Course", second.EntityType);
            Assert.Equal("Department", third.EntityType);
        }

        [Fact]
        public void ReceiveNotification_DequeuesMessage()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            _service.ReceiveNotification(); // consume it
            var second = _service.ReceiveNotification();

            Assert.Null(second);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op in the in-memory implementation
            var ex = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(ex);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var ex = Record.Exception(() => service.Dispose());
            Assert.Null(ex);
        }

        [Fact]
        public void SendNotification_OverflowQueue_TrimsOldMessages()
        {
            // Send more than max queue length (500) to test overflow behavior
            for (int i = 0; i < 510; i++)
            {
                _service.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
            }

            // Should still be able to receive notifications (queue is capped)
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
        }
    }
}

