using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Linq;
using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class ModelValidationTests
    {
        private IList<ValidationResult> ValidateModel(object model)
        {
            var results = new List<ValidationResult>();
            var context = new ValidationContext(model, null, null);
            Validator.TryValidateObject(model, context, results, true);
            return results;
        }

        #region Person / Student

        [Fact]
        public void Student_ValidModel_PassesValidation()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var results = ValidateModel(student);

            Assert.Empty(results);
        }

        [Fact]
        public void Student_MissingLastName_FailsValidation()
        {
            var student = new Student
            {
                FirstMidName = "John",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var results = ValidateModel(student);

            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_MissingFirstName_FailsValidation()
        {
            var student = new Student
            {
                LastName = "Smith",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var results = ValidateModel(student);

            Assert.Contains(results, r => r.MemberNames.Contains("FirstMidName"));
        }

        [Fact]
        public void Student_LastNameTooLong_FailsValidation()
        {
            var student = new Student
            {
                LastName = new string('A', 51),
                FirstMidName = "John",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var results = ValidateModel(student);

            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_FirstNameTooLong_FailsValidation()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = new string('A', 51),
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var results = ValidateModel(student);

            Assert.Contains(results, r => r.MemberNames.Contains("FirstMidName"));
        }

        [Fact]
        public void Person_FullName_ReturnsLastNameCommaFirstName()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John"
            };

            Assert.Equal("Smith, John", student.FullName);
        }

        #endregion

        #region Instructor

        [Fact]
        public void Instructor_ValidModel_PassesValidation()
        {
            var instructor = new Instructor
            {
                LastName = "Jones",
                FirstMidName = "Alice",
                HireDate = new DateTime(2020, 1, 15)
            };

            var results = ValidateModel(instructor);

            Assert.Empty(results);
        }

        [Fact]
        public void Instructor_MissingLastName_FailsValidation()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Alice",
                HireDate = new DateTime(2020, 1, 15)
            };

            var results = ValidateModel(instructor);

            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        #endregion

        #region Course

        [Fact]
        public void Course_ValidModel_PassesValidation()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Physics",
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);

            Assert.Empty(results);
        }

        [Fact]
        public void Course_TitleTooShort_FailsValidation()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Ph",
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);

            Assert.Contains(results, r => r.MemberNames.Contains("Title"));
        }

        [Fact]
        public void Course_TitleTooLong_FailsValidation()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = new string('A', 51),
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);

            Assert.Contains(results, r => r.MemberNames.Contains("Title"));
        }

        [Fact]
        public void Course_CreditsTooHigh_FailsValidation()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Physics",
                Credits = 6,
                DepartmentID = 1
            };

            var results = ValidateModel(course);

            Assert.Contains(results, r => r.MemberNames.Contains("Credits"));
        }

        [Fact]
        public void Course_CreditsNegative_FailsValidation()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Physics",
                Credits = -1,
                DepartmentID = 1
            };

            var results = ValidateModel(course);

            Assert.Contains(results, r => r.MemberNames.Contains("Credits"));
        }

        [Fact]
        public void Course_CreditsZero_PassesValidation()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Physics",
                Credits = 0,
                DepartmentID = 1
            };

            var results = ValidateModel(course);

