[Fact]
public void Edit_Post_WithValidImage_UpdatesImagePath()
{
    // Detach the tracked entity
    var tracked = _context.Courses.Find(1050);
    _context.Entry(tracked).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

    var course = new Course
    {
        CourseID = 1050,
        Title = "Chemistry",
        Credits = 3,
        DepartmentID = 1
    };

    var fileContent = new byte[] { 0xFF, 0xD8, 0xFF }; // JPEG header bytes
    var mockFile = new Mock<IFormFile>();
    mockFile.Setup(f => f.FileName).Returns("material.jpg");
    mockFile.Setup(f => f.Length).Returns(fileContent.Length);
    mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()))
        .Callback<Stream>(s => s.Write(fileContent, 0, fileContent.Length));

    var result = _controller.Edit(course, mockFile.Object);

    Assert.IsType<RedirectToActionResult>(result);
}

